import{_ as o,o as a,c as t,a0 as r}from"./chunks/framework.DZNqfkJl.js";const u=JSON.parse('{"title":"Required Tools","description":"","frontmatter":{},"headers":[],"relativePath":"en/tools.md","filePath":"en/tools.md"}'),n={name:"en/tools.md"};function s(l,e,i,d,c,h){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="required-tools" tabindex="-1">Required Tools <a class="header-anchor" href="#required-tools" aria-label="Permalink to &quot;Required Tools&quot;">​</a></h1><p>To develop and run the <strong>Structo</strong> project, you need to install the following tools in your development environment.</p><p>The project consists of a .NET backend and a Nuxt.js frontend, and interacts with SQL Server and MongoDB databases.</p><h2 id="core-tools-required" tabindex="-1">Core Tools (Required) <a class="header-anchor" href="#core-tools-required" aria-label="Permalink to &quot;Core Tools (Required)&quot;">​</a></h2><h3 id="_1-node-js-22-npm" tabindex="-1">1. Node.js 22+ &amp; npm <a class="header-anchor" href="#_1-node-js-22-npm" aria-label="Permalink to &quot;1. Node.js 22+ &amp; npm&quot;">​</a></h3><p>Required for the frontend (Nuxt) and for the documentation (VitePress).</p><ul><li><strong>Purpose</strong>: Run the Nuxt development server, build the frontend, and manage the JavaScript ecosystem dependencies.</li><li><strong>Installation</strong>: Install version <strong>22 or higher</strong>. You can download it from <a href="https://nodejs.org/" target="_blank" rel="noreferrer">nodejs.org</a> or use a version manager like <code>nvm</code>.</li></ul><h3 id="_2-net-sdk-10" tabindex="-1">2. .NET SDK 10 <a class="header-anchor" href="#_2-net-sdk-10" aria-label="Permalink to &quot;2. .NET SDK 10&quot;">​</a></h3><p>Required for the C# backend. Make sure to install version <strong>10</strong>.</p><ul><li><strong>Purpose</strong>: Build and run the <code>Structo.sln</code> solution and the various projects located in the folder where the backend is hosted.</li><li><strong>Installation</strong>: Download and install the .NET 10 SDK from the <a href="https://dotnet.microsoft.com/download" target="_blank" rel="noreferrer">official Microsoft page</a>.</li></ul><h4 id="entity-framework-core-tools-dotnet-ef" tabindex="-1">Entity Framework Core Tools (dotnet-ef) <a class="header-anchor" href="#entity-framework-core-tools-dotnet-ef" aria-label="Permalink to &quot;Entity Framework Core Tools (dotnet-ef)&quot;">​</a></h4><p>Additionally, the EF Core global tool is required to manage database migrations.</p><ul><li><strong>Installation</strong>: Run the following command in your terminal after installing the .NET SDK:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tool</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dotnet-ef</span></span></code></pre></div></li></ul><h3 id="_3-sql-server" tabindex="-1">3. SQL Server <a class="header-anchor" href="#_3-sql-server" aria-label="Permalink to &quot;3. SQL Server&quot;">​</a></h3><p>Required as the relational database of the system.</p><ul><li><strong>Purpose</strong>: Store the main information of the platform.</li><li><strong>Installation</strong>: You can install <a href="https://www.microsoft.com/en-us/sql-server/sql-server-downloads" target="_blank" rel="noreferrer">SQL Server Developer Edition</a> locally.</li></ul><h3 id="_4-mongodb" tabindex="-1">4. MongoDB <a class="header-anchor" href="#_4-mongodb" aria-label="Permalink to &quot;4. MongoDB&quot;">​</a></h3><p>Required as the NoSQL database of the system.</p><ul><li><strong>Purpose</strong>: Store documents and non-relational data of the platform.</li><li><strong>Installation</strong>: Download and install <a href="https://www.mongodb.com/try/download/community" target="_blank" rel="noreferrer">MongoDB Community Server</a>.</li></ul><h3 id="_5-git" tabindex="-1">5. Git <a class="header-anchor" href="#_5-git" aria-label="Permalink to &quot;5. Git&quot;">​</a></h3><p>Required for version control.</p><ul><li><strong>Purpose</strong>: Clone the repository and manage code changes.</li><li><strong>Installation</strong>: Available at <a href="https://git-scm.com/" target="_blank" rel="noreferrer">git-scm.com</a>.</li></ul><hr><h2 id="optional-recommended-tools" tabindex="-1">Optional / Recommended Tools <a class="header-anchor" href="#optional-recommended-tools" aria-label="Permalink to &quot;Optional / Recommended Tools&quot;">​</a></h2><h3 id="docker-and-docker-compose-optional" tabindex="-1">Docker and Docker Compose (Optional) <a class="header-anchor" href="#docker-and-docker-compose-optional" aria-label="Permalink to &quot;Docker and Docker Compose (Optional)&quot;">​</a></h3><p>If you prefer not to install services (like databases) directly on your local machine, you can run them using containers.</p><ul><li><strong>Purpose</strong>: Run infrastructure dependencies locally in an isolated manner.</li><li><strong>Installation</strong>: Install <a href="https://www.docker.com/products/docker-desktop/" target="_blank" rel="noreferrer">Docker Desktop</a> (Windows/Mac) or Docker Engine (Linux). Make sure <code>docker-compose</code> is available.</li></ul><h3 id="dbeaver-recommended" tabindex="-1">DBeaver (Recommended) <a class="header-anchor" href="#dbeaver-recommended" aria-label="Permalink to &quot;DBeaver (Recommended)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: Universal visual client for managing relational databases, very useful for interacting with SQL Server.</li><li><strong>Installation</strong>: Available for free at <a href="https://dbeaver.io/" target="_blank" rel="noreferrer">dbeaver.io</a>.</li></ul><p><em>(Alternatives: SQL Server Management Studio (SSMS) or Azure Data Studio).</em></p><h3 id="mongodb-compass-recommended" tabindex="-1">MongoDB Compass (Recommended) <a class="header-anchor" href="#mongodb-compass-recommended" aria-label="Permalink to &quot;MongoDB Compass (Recommended)&quot;">​</a></h3><ul><li><strong>Purpose</strong>: Official graphical interface to explore and interact with your MongoDB collections and databases.</li><li><strong>Installation</strong>: You can download it from <a href="https://www.mongodb.com/products/tools/compass" target="_blank" rel="noreferrer">mongodb.com/products/tools/compass</a>.</li></ul>',32)])])}const p=o(n,[["render",s]]);export{u as __pageData,p as default};
